public class Reflector { public static void main(String[] args) { try { Class<?> clazz = Class.forName("net.minecraft.world.item.equipment.Equippable"); System.out.println("Constructors:"); for (java.lang.reflect.Constructor<?> c : clazz.getDeclaredConstructors()) { System.out.println(c); } System.out.println("\nMethods:"); for (java.lang.reflect.Method m : clazz.getDeclaredMethods()) { System.out.println(m); } } catch (Exception e) { e.printStackTrace(); } } }
